'use client'

import { useEffect, useState, useRef } from 'react'
import dynamic from 'next/dynamic'
import { createClient } from '@/lib/supabase/client'
import { useTheme } from 'next-themes'
import { Loader2, Maximize2, Minimize2 } from 'lucide-react'
import { Button } from '@/components/ui/button'

// Dynamically import ForceGraph2D with no SSR
const ForceGraph2D = dynamic(() => import('react-force-graph-2d'), {
    ssr: false,
    loading: () => <div className="flex items-center justify-center h-64"><Loader2 className="animate-spin" /></div>
})

interface KnowledgeGraphProps {
    centerPostId: string
}

export function KnowledgeGraph({ centerPostId }: KnowledgeGraphProps) {
    const [graphData, setGraphData] = useState({ nodes: [], links: [] })
    const [loading, setLoading] = useState(true)
    const [expanded, setExpanded] = useState(false)
    const [dimensions, setDimensions] = useState({ width: 0, height: 0 })
    const containerRef = useRef<HTMLDivElement>(null)
    const graphRef = useRef<any>()
    const supabase = createClient()
    const { theme } = useTheme()

    useEffect(() => {
        fetchGraphData()
    }, [centerPostId])

    useEffect(() => {
        const updateDimensions = () => {
            if (containerRef.current) {
                const { width, height } = containerRef.current.getBoundingClientRect()
                setDimensions({ width, height })
            }
        }

        // Initial measurement
        updateDimensions()

        // Resize observer
        const resizeObserver = new ResizeObserver(() => {
            updateDimensions()
        })

        if (containerRef.current) {
            resizeObserver.observe(containerRef.current)
        }

        return () => resizeObserver.disconnect()
    }, [expanded])

    const fetchGraphData = async () => {
        try {
            // 1. Fetch the center post
            const { data: centerPost } = await supabase
                .from('posts')
                .select('id, title, forked_from_id')
                .eq('id', centerPostId)
                .single()

            if (!centerPost) return

            const nodes = new Map()
            const links = []

            // Add center node
            nodes.set(centerPost.id, { id: centerPost.id, title: centerPost.title, group: 'center', val: 20 })

            // 2. Fetch parent (if exists)
            if (centerPost.forked_from_id) {
                const { data: parent } = await supabase
                    .from('posts')
                    .select('id, title')
                    .eq('id', centerPost.forked_from_id)
                    .single()

                if (parent) {
                    nodes.set(parent.id, { id: parent.id, title: parent.title, group: 'parent', val: 15 })
                    links.push({ source: parent.id, target: centerPost.id, type: 'fork' })
                }
            }

            // 3. Fetch children (forks)
            const { data: forks } = await supabase
                .from('posts')
                .select('id, title')
                .eq('forked_from_id', centerPostId)

            forks?.forEach(fork => {
                nodes.set(fork.id, { id: fork.id, title: fork.title, group: 'child', val: 10 })
                links.push({ source: centerPost.id, target: fork.id, type: 'fork' })
            })

            // 4. Fetch citations (where this post is target)
            const { data: citations } = await supabase
                .from('citations')
                .select('source_post_id, posts!citations_source_post_id_fkey(id, title)')
                .eq('target_post_id', centerPostId)

            citations?.forEach((citation: any) => {
                const source = citation.posts
                if (source) {
                    nodes.set(source.id, { id: source.id, title: source.title, group: 'citation', val: 8 })
                    links.push({ source: source.id, target: centerPost.id, type: 'citation' })
                }
            })

            setGraphData({
                nodes: Array.from(nodes.values()),
                links: links
            })
        } catch (error) {
            console.error('Error fetching graph data:', error)
        } finally {
            setLoading(false)
        }
    }

    const isDark = theme === 'dark'

    return (
        <div
            ref={containerRef}
            className={`relative border border-gray-200 dark:border-dark-border rounded-lg overflow-hidden bg-gray-50 dark:bg-dark-surface transition-all duration-300 ${expanded ? 'fixed inset-4 z-50 shadow-2xl' : 'h-[400px] w-full'}`}
        >
            <div className="absolute top-2 right-2 z-10">
                <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => setExpanded(!expanded)}
                    className="bg-white/80 dark:bg-black/50 backdrop-blur-sm"
                >
                    {expanded ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
                </Button>
            </div>

            {!loading && dimensions.width > 0 && (
                <ForceGraph2D
                    ref={graphRef}
                    graphData={graphData}
                    nodeLabel="title"
                    nodeColor={node => {
                        switch (node.group) {
                            case 'center': return '#3B82F6' // Blue
                            case 'parent': return '#8B5CF6' // Purple
                            case 'child': return '#10B981' // Green
                            case 'citation': return '#F59E0B' // Amber
                            default: return '#9CA3AF'
                        }
                    }}
                    linkColor={() => isDark ? '#4B5563' : '#D1D5DB'}
                    backgroundColor={isDark ? '#111827' : '#F9FAFB'}
                    width={dimensions.width}
                    height={dimensions.height}
                    onNodeClick={node => {
                        window.location.href = `/post/${node.id}`
                    }}
                    cooldownTicks={100}
                />
            )}
        </div>
    )
}
